// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.junit.jupiter.api.Test;

class LmdbNativeExplainTest {

	@Test
	void runtimePlanKeepsTheFirstObservationInsteadOfRebuildingForEveryInvocation() {
		SingletonSet target = new SingletonSet();
		target.setRuntimeTelemetryEnabled(true);
		NativeSlotLayout layout = layout();

		LmdbNativeExplain.recordRuntimeEntryPlan(target, SingletonPlan.INSTANCE, layout, 1L);
		LmdbNativeExplain.recordRuntimeEntryPlan(target, EmptyPlan.INSTANCE, layout, 2L);

		assertThat(target.getStringMetricActual(LmdbNativeExplain.RUNTIME_ENTRY_PLAN)).isEqualTo("Singleton");
		assertThat(target.getStringMetricActual(LmdbNativeExplain.INITIAL_BOUND_MASK))
				.isEqualTo("0x1 [?first#0]");
	}

	@Test
	void executionStrategySummarizesDistinctObservedStrategiesDeterministically() {
		SingletonSet target = new SingletonSet();
		target.setExecutionSummaryEnabled(true);

		LmdbNativeExplain.recordExecutionPath(target, "nestedLoop");
		LmdbNativeExplain.recordExecutionPath(target, "nestedLoop");
		LmdbNativeExplain.recordExecutionPath(target, "batch");

		assertThat(target.getStringMetricActual(LmdbNativeExplain.EXECUTION_PATH))
				.isEqualTo("batch | nestedLoop");
	}

	@Test
	void clonedExpressionsDoNotShareMutableExecutionSummaries() {
		SingletonSet target = new SingletonSet();
		target.setExecutionSummaryEnabled(true);
		LmdbNativeExplain.recordExecutionPath(target, "nestedLoop");
		SingletonSet clone = target.clone();

		LmdbNativeExplain.recordExecutionPath(clone, "batch");
		LmdbNativeExplain.recordExecutionPath(target, "chunkPipeline");

		assertThat(target.getStringMetricActual(LmdbNativeExplain.EXECUTION_PATH))
				.isEqualTo("chunkPipeline | nestedLoop");
		assertThat(clone.getStringMetricActual(LmdbNativeExplain.EXECUTION_PATH))
				.isEqualTo("batch | nestedLoop");
	}

	@Test
	void stickyFilterMaskDoesNotInventSixtyFourNamedSlots() {
		FilterPlan filter = new FilterPlan(SingletonPlan.INSTANCE, ignored -> true, -1L);

		assertThat(LmdbNativeExplain.describe(filter, layout()))
				.contains("Filter(mask=sticky")
				.doesNotContain("#63");
	}

	private static NativeSlotLayout layout() {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("first", 0, "second", 1), null);
		layout.freeze(List.of("first", "second"));
		return layout;
	}
}
